function BridalMakeup() {
    const makeupArtists = [
        {
            name: "Glow Beauty Studio",
            experience: "5 Years",
            service: "Bridal Makeup",
            package:
                "Bridal makeup, hairstyling, skincare preparation, and touch-up session.",
            contact: "glowbeauty@email.com",
            price: "$350 package",
            image: "https://cdn-icons-png.flaticon.com/512/4140/4140048.png",
        },

        {
            name: "Diamond Beauty",
            experience: "7 Years",
            service: "Luxury Bridal Makeup",
            package:
                "Premium bridal makeup, hairstyle, lashes, and wedding day beauty support.",
            contact: "diamondbeauty@email.com",
            price: "$600 package",
            image: "https://cdn-icons-png.flaticon.com/512/6997/6997662.png",
        },

        {
            name: "Pink Rose Makeup",
            experience: "4 Years",
            service: "Soft Bridal Makeup",
            package:
                "Natural bridal makeup, elegant hairstyle, and beauty consultation.",
            contact: "pinkrose@email.com",
            price: "$280 package",
            image: "https://cdn-icons-png.flaticon.com/512/4140/4140077.png",
        },
    ];

    function requestMakeup(name) {
        alert("Your request has been sent to " + name);
    }

    return (
        <section className="page-section">
            <div className="page-header">
                <h1>Bridal Makeup</h1>

                <p>
                    Find professional makeup artists for bridal beauty,
                    hairstyling, and wedding preparation services.
                </p>
            </div>

            <section className="cards">
                {makeupArtists.map((artist, index) => (
                    <div className="card" key={index}>
                        <img
                            src={artist.image}
                            alt={artist.name}
                            className="service-image"
                        />

                        <h3>{artist.name}</h3>

                        <p><strong>Service:</strong> {artist.service}</p>
                        <p><strong>Package Includes:</strong> {artist.package}</p>
                        <p><strong>Experience:</strong> {artist.experience}</p>
                        <p><strong>Email:</strong> {artist.contact}</p>
                        <p><strong>Price:</strong> {artist.price}</p>

                        <button
                            className="request-btn"
                            onClick={() => requestMakeup(artist.name)}
                        >
                            Request Service
                        </button>
                    </div>
                ))}
            </section>
        </section>
    );
}

export default BridalMakeup;
